import React from 'react';
import { Input, Select } from '@linm-soft/common-components';
import { AccountSearchInput, LineMaterialSearchCell, MaterialLineTableHeaders } from '../../../../../components/search';
import { erpFinanceAccountSearchApi, formatAccountDisplay } from '../../../../../components/search/accountSearchApi';
import { formatMoneyVnd } from '../../../../../utils/formatters';
import { LocaleNumberInput } from '../../../../../components/form/LocaleNumberInput';
import { isEditingMode } from '../../../../../components/form';
import { lineAmount, lineTax } from '../mappers/purchaseInvoiceMappers';
import type { usePurchaseInvoiceFormController } from '../hooks/usePurchaseInvoiceFormController';

type Vm = ReturnType<typeof usePurchaseInvoiceFormController>;

export const PurchaseInvoiceLinesSection: React.FC<{ vm: Vm }> = ({ vm }) => {
  const df = vm.styles;
  const {
    tid,
    toolbarMode,
    isStatusLocked,
    fieldLock,
    lines,
    fieldErrors,
    taxRateSelectOptions,
    resolveUnitName,
    updateLine,
    addLine,
    removeLine,
  } = vm;

  const { isReadOnly, searchDisabled, searchViewClass, viewSectionClass } = fieldLock;
  const lineAccountSearchClass = [searchViewClass, df.lineAccountSearch].filter(Boolean).join(' ');

  return (
    <div className={`${df.section} ${viewSectionClass ?? ''}`} data-testid={tid('section-lines')}>
      <h2 className={df.sectionTitle}>Chi tiết hàng hóa</h2>
      <div className={df.tableWrapper}>
        <table className={df.linesTable}>
          <thead>
            <tr>
              <MaterialLineTableHeaders />
              <th className={df.thUnit}>ĐVT</th>
              <th className={df.thAmount}>SL</th>
              <th className={df.thAmount}>Đơn giá</th>
              <th>Thuế %</th>
              <th>TK Nợ</th>
              <th className={df.thAmount}>Thành tiền</th>
              {isEditingMode(toolbarMode) && !isStatusLocked && <th className={df.thDel} />}
            </tr>
          </thead>
          <tbody>
            {lines.map((line, idx) => (
              <tr key={idx} data-testid={tid(`line-${idx + 1}`)}>
                <LineMaterialSearchCell
                  materialCode={line.materialCode}
                  materialName={line.materialName}
                  cellId={tid(`line-${idx + 1}-material`)}
                  disabled={isReadOnly}
                  testId={tid(`line-${idx + 1}-material`)}
                  error={fieldErrors.lines?.[idx]?.materialCode}
                  onSelect={m =>
                    updateLine(idx, {
                      materialCode: m.code,
                      materialName: m.name,
                      unitCode: m.unitCode ?? line.unitCode,
                      unitName: resolveUnitName(m.unitCode ?? line.unitCode),
                      unitPrice: m.standardCost ?? line.unitPrice,
                      debitAccountCode: m.accountCode ?? line.debitAccountCode,
                    })
                  }
                  onClear={() => updateLine(idx, { materialCode: '', materialName: '', unitCode: '', unitName: '' })}
                />
                <td data-testid={tid(`line-${idx + 1}-unitCode`)}>
                  <Input value={line.unitName || resolveUnitName(line.unitCode)} disabled readOnly />
                </td>
                <td id={tid(`line-${idx + 1}-quantity`)} data-testid={tid(`line-${idx + 1}-quantity`)}>
                  <LocaleNumberInput
                    format="quantity"
                    value={line.quantity}
                    error={fieldErrors.lines?.[idx]?.quantity}
                    onChange={q => updateLine(idx, { quantity: q })}
                    disabled={isReadOnly}
                  />
                </td>
                <td id={tid(`line-${idx + 1}-unitPrice`)} data-testid={tid(`line-${idx + 1}-unitPrice`)}>
                  <LocaleNumberInput
                    format="money"
                    value={line.unitPrice}
                    error={fieldErrors.lines?.[idx]?.unitPrice}
                    onChange={p => updateLine(idx, { unitPrice: p })}
                    disabled={isReadOnly}
                  />
                </td>
                <td id={tid(`line-${idx + 1}-taxRate`)} data-testid={tid(`line-${idx + 1}-taxRate`)}>
                  <Select
                    value={String(line.taxRate)}
                    error={fieldErrors.lines?.[idx]?.taxRate}
                    onChange={e => updateLine(idx, { taxRate: Number(e.target.value) })}
                    options={taxRateSelectOptions}
                    disabled={isReadOnly}
                  />
                </td>
                <td id={tid(`line-${idx + 1}-debitAccountCode`)} data-testid={tid(`line-${idx + 1}-debitAccountCode`)}>
                  <AccountSearchInput
                    api={erpFinanceAccountSearchApi}
                    value={line.debitAccountCode}
                    primaryDisplay={formatAccountDisplay(line.debitAccountCode, '')}
                    onChange={a => updateLine(idx, { debitAccountCode: a.code })}
                    onClear={() => updateLine(idx, { debitAccountCode: '' })}
                    showSecondaryInput={false}
                    error={fieldErrors.lines?.[idx]?.debitAccountCode}
                    className={lineAccountSearchClass}
                    disabled={searchDisabled}
                  />
                </td>
                <td style={{ textAlign: 'right', paddingTop: 10 }}>
                  {formatMoneyVnd(lineAmount(line) + lineTax(line))}
                </td>
                {isEditingMode(toolbarMode) && !isStatusLocked && (
                  <td>
                    <button
                      type="button"
                      className={df.btnDeleteLine}
                      onClick={() => removeLine(idx)}
                      title="Xóa dòng"
                    >
                      ×
                    </button>
                  </td>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      {isEditingMode(toolbarMode) && !isStatusLocked && (
        <button type="button" className={df.btnAddLine} data-testid={tid('add-line-btn')} onClick={addLine}>
          + Thêm dòng
        </button>
      )}
    </div>
  );
};
