import React from 'react';
import { Input, SearchInput } from '@linm-soft/common-components';
import { AccountSearchInput } from '../../../../../components/search';
import { erpFinanceAccountSearchApi, formatAccountDisplay } from '../../../../../components/search/accountSearchApi';
import { LocaleNumberInput } from '../../../../../components/form/LocaleNumberInput';
import { fieldPlaceholder } from '../../../../../components/form';
import type { usePurchaseInvoiceFormController } from '../hooks/usePurchaseInvoiceFormController';

type Vm = ReturnType<typeof usePurchaseInvoiceFormController>;

export const PurchaseInvoiceHeaderSection: React.FC<{ vm: Vm }> = ({ vm }) => {
  const df = vm.styles;
  const {
    tid,
    toolbarMode,
    isStatusLocked,
    fieldLock,
    invoiceDate,
    setInvoiceDate,
    code,
    eInvoiceNo,
    setEInvoiceNo,
    currencyCode,
    setCurrencyCode,
    currencyLabel,
    exchangeRate,
    setExchangeRate,
    supplierSearchConfig,
    supplierId,
    supplierCode,
    supplierName,
    setSupplierId,
    setSupplierCode,
    setSupplierName,
    creditAccountCode,
    creditAccountName,
    vatAccountCode,
    vatAccountName,
    setCreditAccountCode,
    setCreditAccountName,
    setVatAccountCode,
    setVatAccountName,
    fieldErrors,
    patchHeaderFieldError,
  } = vm;

  const {
    isReadOnly,
    fieldLockProps,
    staticFieldProps,
    searchDisabled,
    searchViewClass,
    viewSectionClass,
  } = fieldLock;

  const searchFieldClass = [searchViewClass, df.embeddedSearch].filter(Boolean).join(' ');

  return (
    <div className={`${df.section} ${viewSectionClass ?? ''}`} data-testid={tid('section-header')}>
      <h2 className={df.sectionTitle}>Thông tin hóa đơn</h2>
      <div className={df.row4}>
        <div className={df.field} id={tid('field-invoiceDate')} data-testid={tid('field-invoiceDate')}>
          <label className={df.label}>Ngày HĐ *</label>
          <Input
            type="date"
            value={invoiceDate}
            error={fieldErrors.invoiceDate}
            onChange={e => {
              setInvoiceDate(e.target.value);
              patchHeaderFieldError('invoiceDate', e.target.value);
            }}
            {...fieldLockProps}
          />
        </div>
        <div className={df.field} data-testid={tid('field-code')}>
          <label className={df.label}>Số chứng từ</label>
          <Input
            value={code}
            {...staticFieldProps}
            placeholder={fieldPlaceholder(toolbarMode, 'Tự động sinh', { isStatusLocked })}
          />
        </div>
        <div className={df.field} data-testid={tid('field-eInvoiceNo')}>
          <label className={df.label}>Số HĐ điện tử</label>
          <Input value={eInvoiceNo} onChange={e => setEInvoiceNo(e.target.value)} {...fieldLockProps} />
        </div>
        <div className={df.field} data-testid={tid('field-currencyCode')}>
          <label className={df.label}>Ngoại tệ</label>
          <Input
            value={currencyCode || currencyLabel}
            onChange={e => setCurrencyCode(e.target.value.toUpperCase())}
            {...fieldLockProps}
          />
        </div>
      </div>
      <div className={df.row4}>
        <div className={df.field} data-testid={tid('field-exchangeRate')}>
          <label className={df.label}>Tỷ giá</label>
          <LocaleNumberInput
            format="money"
            value={exchangeRate}
            onChange={v => setExchangeRate(v)}
            disabled={isReadOnly}
          />
        </div>
        <div className={`${df.spanCol2} ${df.field}`} id={tid('field-supplierId')} data-testid={tid('field-supplierId')}>
          <label className={df.label}>Nhà cung cấp *</label>
          <SearchInput
            config={supplierSearchConfig}
            value={supplierId}
            primaryDisplay={supplierCode}
            secondaryDisplay={supplierName}
            onChange={c => {
              setSupplierId(c.customerId);
              setSupplierCode(c.code);
              setSupplierName(c.name);
              patchHeaderFieldError('supplierId', c.customerId);
            }}
            onClear={() => {
              setSupplierId('');
              setSupplierCode('');
              setSupplierName('');
              patchHeaderFieldError('supplierId', '');
            }}
            className={searchFieldClass}
            showLabel={false}
            error={fieldErrors.supplierId}
            disabled={searchDisabled}
          />
        </div>
        <div className={df.field} id={tid('field-creditAccountCode')} data-testid={tid('field-creditAccountCode')}>
          <label className={df.label}>TK Có (công nợ) *</label>
          <AccountSearchInput
            api={erpFinanceAccountSearchApi}
            value={creditAccountCode}
            primaryDisplay={formatAccountDisplay(creditAccountCode, creditAccountName)}
            secondaryDisplay={creditAccountName}
            onChange={a => {
              setCreditAccountCode(a.code);
              setCreditAccountName(a.name);
              patchHeaderFieldError('creditAccountCode', a.code);
            }}
            onClear={() => {
              setCreditAccountCode('');
              setCreditAccountName('');
              patchHeaderFieldError('creditAccountCode', '');
            }}
            showLabel={false}
            showSecondaryInput={false}
            error={fieldErrors.creditAccountCode}
            className={searchFieldClass}
            disabled={searchDisabled}
            placeholder="331..."
          />
        </div>
        <div className={df.field} id={tid('field-vatAccountCode')} data-testid={tid('field-vatAccountCode')}>
          <label className={df.label}>TK thuế GTGT *</label>
          <AccountSearchInput
            api={erpFinanceAccountSearchApi}
            value={vatAccountCode}
            primaryDisplay={formatAccountDisplay(vatAccountCode, vatAccountName)}
            secondaryDisplay={vatAccountName}
            onChange={a => {
              setVatAccountCode(a.code);
              setVatAccountName(a.name);
              patchHeaderFieldError('vatAccountCode', a.code);
            }}
            onClear={() => {
              setVatAccountCode('');
              setVatAccountName('');
              patchHeaderFieldError('vatAccountCode', '');
            }}
            showLabel={false}
            showSecondaryInput={false}
            error={fieldErrors.vatAccountCode}
            className={searchFieldClass}
            disabled={searchDisabled}
            placeholder="1331..."
          />
        </div>
      </div>
    </div>
  );
};
